            return this.fail(toolCallId, 'Missing required parameter: query');
        }
        // Validate path if provided
        let searchDir = workDir;
        if (searchPath) {
            try {
                searchDir = this.validatePath(searchPath, workDir);
            }
            catch (err) {
                return this.fail(toolCallId, err.message);
            }
        }
