            }
            else {
                globs = Object.values(LANG_GLOBS).flat();
            }
            // Find files
            const files = await fg(globs, {
                cwd: searchDir,
                ignore: IGNORE_DIRS,
                absolute: true,
                onlyFiles: true,
                followSymbolicLinks: false,
            });
