                            framework,
                            command: fullCommand,
                            url: `http://localhost:${port}`,
                            port,
                            pid: this.process?.pid ?? 0,
                            managed: true,
                        };
                        this.state = state;
                        this.emit("started", state);
                        resolve(state);
                        return;
                    }
