            files = await fg(globPattern ?? '**/*', {
                cwd: searchDir,
                absolute: true,
                ignore: ['**/node_modules/**', '**/.git/**', '**/dist/**', '**/build/**'],
                onlyFiles: true,
                followSymbolicLinks: false,
            });
        }
